// WeatherApp.jsx
import React from "react";
import WeatherOverlay from "./WeatherOverlay";

export default function WeatherApp() {
  const condition = "Partly Cloudy"; // later replace with dynamic prop
  const isDay = true; // later replace with actual day/night logic

  return (
    <div className="relative h-screen w-full overflow-hidden">
      {/* Weather Overlay Background */}
      <WeatherOverlay condition={condition} isDay={isDay} />

      {/* Foreground content */}
      <div className="relative z-10 flex flex-col h-full w-full bg-gradient-to-b from-white/50 to-white/80 backdrop-blur-sm">
        {/* Header */}
        <div className="text-center py-6">
          <h1 className="text-4xl font-bold text-gray-800">
            Today in <span className="text-purple-500">Atlanta</span>
          </h1>
          <p className="text-lg text-gray-600 mt-1">Partly Cloudy</p>
        </div>

        {/* Weather Cards */}
        <div className="flex-1 px-6 pb-6 flex items-center justify-center">
          <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-6">
            {[
              { label: "Temperature", value: "36.2°C" },
              { label: "Humidity", value: "70%" },
              { label: "Wind Speed", value: "12 km/h" },
              { label: "UV Index", value: "5 (Moderate)" },
            ].map((card, idx) => (
              <div
                key={idx}
                className="transition-all duration-300 transform hover:scale-105 hover:shadow-2xl hover:bg-purple-200/50 bg-white/50 backdrop-blur-lg rounded-xl shadow-md p-6"
              >
                <p className="text-md font-medium text-gray-600">{card.label}</p>
                <p className="text-3xl font-bold text-gray-800 mt-2">{card.value}</p>
              </div>
            ))}
          </div>
        </div>

        {/* Bottom Nav */}
        <div className="h-16 border-t bg-white/70 shadow-inner flex items-center justify-around backdrop-blur-md z-20">
          {[
            { icon: "☀️", label: "Weather" },
            { icon: "📡", label: "Radar" },
            { icon: "💬", label: "Community" },
            { icon: "🤖", label: "Chat" },
          ].map((tab, idx) => (
            <button
              key={idx}
              className="flex flex-col items-center text-gray-600 hover:text-purple-600 transition duration-300"
            >
              <span className="text-xl">{tab.icon}</span>
              <span className="text-xs">{tab.label}</span>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}
